import React, { useState } from "react";
import FileUploadInput from "./FileUploadInput";

const AssignmentForm = () => {
  const [title, setTitle] = useState("");
  const [instructions, setInstructions] = useState("");
  const [file, setFile] = useState(null);
  const [posted, setPosted] = useState(false);

  const handleSubmit = (e) => {
    e.preventDefault();
    if (!title || !file) {
      alert("Please enter a title and upload a file.");
      return;
    }
    setPosted(true);
  };

  return (
    <form onSubmit={handleSubmit} style={styles.form}>
      <h2>📌 Create Assignment</h2>
      <input
        type="text"
        placeholder="Assignment Title"
        value={title}
        onChange={(e) => setTitle(e.target.value)}
        style={styles.input}
      />
      <textarea
        placeholder="Instructions (optional)"
        value={instructions}
        onChange={(e) => setInstructions(e.target.value)}
        rows="4"
        style={styles.textarea}
      />
      <FileUploadInput onFileSelect={(f) => setFile(f)} />
      <button type="submit" style={styles.button}>Post Assignment</button>
      {posted && (
        <p style={{ color: "green", marginTop: 20 }}>
          ✅ Assignment posted successfully!
        </p>
      )}
    </form>
  );
};

const styles = {
  form: {
    backgroundColor: "#fff",
    padding: 30,
    borderRadius: 10,
    maxWidth: 500,
    margin: "40px auto",
    boxShadow: "0 4px 12px rgba(0,0,0,0.1)",
  },
  input: {
    width: "100%",
    padding: 10,
    fontSize: 16,
    marginBottom: 15,
    borderRadius: 6,
    border: "1px solid #ccc",
  },
  textarea: {
    width: "100%",
    padding: 10,
    fontSize: 15,
    borderRadius: 6,
    border: "1px solid #ccc",
    marginBottom: 20,
  },
  button: {
    backgroundColor: "#1a73e8",
    color: "#fff",
    border: "none",
    padding: 12,
    fontSize: 16,
    borderRadius: 5,
    cursor: "pointer",
    width: "100%",
  },
};

export default AssignmentForm;
